def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = 1 / j
            term = ratio ** j
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += weight * term
        if capacity < item * 1.5:
            score *= 2
        elif capacity < item * 3:
            score *= 1.2
        elif capacity > item * 6:
            score *= 0.5
        else:
            for k in range(1, 4):
                if capacity % k == 0:
                    score *= (1 + 0.05 * k)
        if score > 1:
            for m in range(1, 4):
                score /= (1 + 0.1 * m)
        priorities[i] = score
    return priorities
